using Parsis.AutoTrader.Core.Parsing; using Parsis.AutoTrader.Core.Models;
namespace Parsis.AutoTrader.Tests; public class SignalParserTests{[Fact]public void ParsesEnglish(){var r=new SignalParser().Parse("XAUUSD BUY LIMIT 2330-2332 TP1 2338 TP2 2345 TP3 2352 SL 2322");Assert.True(r.Success);Assert.Equal(TradeSide.Buy,r.Signal!.Side);Assert.Equal(EntryMode.Limit,r.Signal.EntryMode);Assert.Equal(3,r.Signal.Targets.Count);}[Fact]public void ParsesPersianDigits(){var r=new SignalParser().Parse("فروش طلا ورود ۲۳۴۱ تا ۲۳۴۲ هدف اول ۲۳۳۵ هدف دوم ۲۳۳۰ هدف سوم ۲۳۲۰ حد ضرر ۲۳۴۸");Assert.True(r.Success);Assert.Equal(TradeSide.Sell,r.Signal!.Side);}}
